import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is wind chill?", a: "Wind chill is the perceived decrease in air temperature felt by exposed skin due to wind. When wind blows across your skin, it removes the thin layer of warm air that your body heat creates, accelerating heat loss. The result is that your body cools faster - you feel colder than the actual air temperature. Wind chill only affects living things that generate heat; it cannot cool inanimate objects below the actual air temperature." },
  { q: "At what wind chill temperature is frostbite a risk?", a: "Frostbite risk by wind chill increases quickly below 0 F. At about -20 F wind chill, frostbite can occur on exposed skin in 30 minutes or less. At about -40 F, frostbite can occur in 10 minutes. Limit outdoor exposure when wind chill falls below 0 F, especially for children and the elderly." },
  { q: "What is the NWS Wind Chill formula?", a: "The US National Weather Service (NWS) formula adopted in 2001: WC = 35.74 + 0.6215T - 35.75(V^0.16) + 0.4275T(V^0.16), where T = air temperature in F and V = wind speed in mph. This formula is valid for T at or below 50 F and V at or above 3 mph." },
  { q: "Does wind chill affect vehicles or pipes?", a: "No. Wind chill only affects living organisms that generate heat and experience convective cooling. Pipes, cars, and buildings cannot be cooled below the actual air temperature by wind. However, the actual air temperature can still freeze pipes." },
  { q: "What is the difference between wind chill and heat index?", a: "Wind chill applies in cold weather and describes how cold wind makes your skin feel. Heat index applies in hot weather and describes how hot high humidity makes the air feel by reducing sweat evaporation. Heat index can make 90 F feel like 105 F; wind chill can make 20 F feel like 0 F." },
  { q: "How do wind speed and temperature each affect wind chill?", a: "Both factors matter, but temperature has more impact overall. For example, at 20 F with 5 mph wind, wind chill is about 13 F. At 20 F with 30 mph wind, it is much colder. Wind's effect diminishes at higher speeds, while temperature's effect is more linear." },
  { q: "Is wind chill relevant for running or cycling?", a: "Yes - for runners and cyclists, wind chill is calculated using ground speed plus headwind speed. A cyclist doing 15 mph into a 15 mph headwind experiences 30 mph effective wind, dramatically increasing wind chill. Tailwinds reduce wind chill. Runners should always factor in their speed when dressing for cold weather runs - sweat-soaked clothing amplifies the effect further." },
  { q: "What should I wear when wind chill is below zero?", a: "Below 0 F wind chill: cover all exposed skin, wear a layered moisture-wicking base layer, insulating mid-layer, and windproof outer layer. Protect ears, nose, fingers, and toes because these extremities lose heat fastest. Wool and synthetic materials retain warmth when wet; cotton does not." },
];

const WIND_CHILL_TABLE = [
  ["30 F", "5 mph", "25 F"],
  ["30 F", "20 mph", "17 F"],
  ["20 F", "5 mph", "13 F"],
  ["20 F", "20 mph", "4 F"],
  ["10 F", "10 mph", "-4 F"],
  ["10 F", "30 mph", "-14 F"],
  ["0 F", "15 mph", "-19 F"],
  ["0 F", "30 mph", "-26 F"],
  ["-10 F", "20 mph", "-39 F"],
  ["-20 F", "15 mph", "-51 F"],
];

export default function WindChillCalculator() {
  const [tempF, setTempF] = useState(20);
  const [windMph, setWindMph] = useState(15);

  const wc = 35.74 + 0.6215 * tempF - 35.75 * Math.pow(windMph, 0.16) + 0.4275 * tempF * Math.pow(windMph, 0.16);
  const wcC = (wc - 32) * 5/9;
  const tempC = (tempF - 32) * 5/9;

  const danger = wc < -40 ? { label: "Extreme Danger - Frostbite in less than 10 min", color: "from-purple-700 to-purple-900" }
    : wc < -20 ? { label: "High Danger - Frostbite in less than 30 min", color: "from-red-600 to-red-800" }
    : wc < 0 ? { label: "Caution - Frostbite risk with prolonged exposure", color: "from-sky-500 to-sky-700" }
    : { label: "Low Risk", color: "from-blue-400 to-blue-600" };

  return (
    <>
      <SEOHead
        title="Free Wind Chill Calculator Online - Calculate Real Feel Temperature Instantly | CalcHive"
        description="Free online wind chill calculator. Calculate what the air really feels like based on temperature and wind speed using the official NWS formula instantly. 100% free for everyone, no signup required."
        canonical="/wind-chill-calculator"
        keywords="free wind chill calculator, wind chill calculator online free, real feel temperature calculator free, NWS wind chill formula calculator free, calculate wind chill free"
        category="Weather Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-purple-600 dark:text-purple-400 bg-purple-50 dark:bg-purple-950/50 px-3 py-1 rounded-full mb-4 inline-block">Weather</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Wind Chill Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free wind chill calculator to calculate wind chill free from air temperature and wind speed using the official NWS formula. This wind chill calculator online free also works as a real feel temperature calculator free and NWS wind chill formula calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="temp" label="Air Temperature (F)" value={tempF} min={-60} max={50} step={1} onChange={setTempF} format={v => `${v} F (${((v-32)*5/9).toFixed(1)} C)`} testId="input-temp" helpText="Wind chill formula valid for 50 F and below" />
            <SliderInput id="wind" label="Wind Speed (mph)" value={windMph} min={3} max={100} step={1} onChange={setWindMph} format={v => `${v} mph`} testId="input-wind" helpText="Formula valid for 3 mph and above" />
          </div>
          <motion.div key={`${tempF}-${windMph}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${danger.color} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Wind Chill Feels Like</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-windchill">{wc.toFixed(1)} F</p>
              <p className="text-white/70 text-sm mt-1">{wcC.toFixed(1)} C - {danger.label}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Actual Temp", value: `${tempF} F / ${tempC.toFixed(1)} C` },
                { label: "Wind Speed", value: `${windMph} mph` },
                { label: "Temp Drop from Wind", value: `${(tempF - wc).toFixed(1)} F colder` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Wind Chill Temperature for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>WC = 35.74 + 0.6215T - 35.75(V^0.16) + 0.4275T(V^0.16)</p>
            <p className="text-xs text-muted-foreground mt-2">T = air temperature (F) - V = wind speed (mph)</p>
            <p className="text-xs text-muted-foreground">Valid range: T at or below 50 F and V at or above 3 mph</p>
            <p className="text-xs text-muted-foreground">Source: US National Weather Service (2001)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the Official NWS Wind Chill Formula Works</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Air Temperature", "Wind Speed", "Wind Chill (Feels Like)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {WIND_CHILL_TABLE.map(([temp, wind, chill]) => {
                  const chillVal = parseFloat(chill);
                  const rowColor = chillVal < -40 ? "bg-purple-50 dark:bg-purple-950/20"
                    : chillVal < -20 ? "bg-red-50 dark:bg-red-950/20"
                    : chillVal < 0 ? "bg-sky-50 dark:bg-sky-950/20"
                    : "";
                  return (
                    <tr key={`${temp}-${wind}`} className={`hover:bg-muted/30 ${rowColor}`}>
                      <td className="py-2.5 px-4 font-bold text-foreground">{temp}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{wind}</td>
                      <td className={`py-2.5 px-4 font-extrabold ${chillVal < -20 ? "text-red-600 dark:text-red-400" : chillVal < 0 ? "text-sky-600 dark:text-sky-400" : "text-foreground"}`}>{chill}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Real Feel Temperature Calculator for Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free weather tool on any device to estimate real-feel conditions quickly without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/wind-chill-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


